#include <stdio.h>
#define MAX_VELICINA 1001

void unesi(char niz[], int velicina) {
	char znak = getchar();
	if (znak == '\n') znak = getchar();
	int i = 0;
	while (i < velicina-1 && znak != '\n') {
		niz[i] = znak;
		i++;
		znak = getchar();
	}
	niz[i] = '\0';
}

int main()
{
    char tekst[MAX_VELICINA];
    char* s = tekst;

    printf("Unesite tekst (do 1000 karaktera): ");
    unesi(tekst, MAX_VELICINA);

	while (*s != '\0') {
		if (*s >= '0' && *s <='9') {
		    while (*s >= '0' && *s <= '9') {
                *s = 'B';
                s++;
            }
		} else {
		    s++;
		}
	}

    printf("\nIzmijenjeni string: %s", tekst);

    return 0;
}
